package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTrimTest {

    private CSVFormat csvFormat;
    private Method trimMethod;

    @BeforeEach
    public void setUp() throws NoSuchMethodException {
        csvFormat = CSVFormat.DEFAULT;
        trimMethod = CSVFormat.class.getDeclaredMethod("trim", CharSequence.class);
        trimMethod.setAccessible(true);
    }

    @Test
    public void testTrimWithString() throws InvocationTargetException, IllegalAccessException {
        String input = "  abc  ";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result);
        assertTrue(result instanceof String);
    }

    @Test
    public void testTrimWithStringNoTrimNeeded() throws InvocationTargetException, IllegalAccessException {
        String input = "abc";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result);
        assertTrue(result instanceof String);
    }

    @Test
    public void testTrimWithNonStringCharSequenceLeadingSpaces() throws InvocationTargetException, IllegalAccessException {
        CharSequence input = new CharSequence() {
            private final String s = "  abc";
            @Override public int length() { return s.length(); }
            @Override public char charAt(int index) { return s.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return s.subSequence(start, end); }
            @Override public String toString() { return s; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertFalse(result instanceof String);
    }

    @Test
    public void testTrimWithNonStringCharSequenceTrailingSpaces() throws InvocationTargetException, IllegalAccessException {
        CharSequence input = new CharSequence() {
            private final String s = "abc  ";
            @Override public int length() { return s.length(); }
            @Override public char charAt(int index) { return s.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return s.subSequence(start, end); }
            @Override public String toString() { return s; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertFalse(result instanceof String);
    }

    @Test
    public void testTrimWithNonStringCharSequenceBothEndsSpaces() throws InvocationTargetException, IllegalAccessException {
        CharSequence input = new CharSequence() {
            private final String s = "  abc  ";
            @Override public int length() { return s.length(); }
            @Override public char charAt(int index) { return s.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return s.subSequence(start, end); }
            @Override public String toString() { return s; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertFalse(result instanceof String);
    }

    @Test
    public void testTrimWithNonStringCharSequenceNoTrimNeeded() throws InvocationTargetException, IllegalAccessException {
        CharSequence input = new CharSequence() {
            private final String s = "abc";
            @Override public int length() { return s.length(); }
            @Override public char charAt(int index) { return s.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return s.subSequence(start, end); }
            @Override public String toString() { return s; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("abc", result.toString());
        assertSame(input, result);
    }

    @Test
    public void testTrimWithEmptyString() throws InvocationTargetException, IllegalAccessException {
        String input = "";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("", result);
        assertTrue(result instanceof String);
    }

    @Test
    public void testTrimWithSpacesOnly() throws InvocationTargetException, IllegalAccessException {
        String input = "    ";
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("", result);
        assertTrue(result instanceof String);
    }

    @Test
    public void testTrimWithNonStringCharSequenceSpacesOnly() throws InvocationTargetException, IllegalAccessException {
        CharSequence input = new CharSequence() {
            private final String s = "    ";
            @Override public int length() { return s.length(); }
            @Override public char charAt(int index) { return s.charAt(index); }
            @Override public CharSequence subSequence(int start, int end) { return s.subSequence(start, end); }
            @Override public String toString() { return s; }
        };
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormat, input);
        assertEquals("", result.toString());
        assertFalse(result instanceof String);
    }
}
